import React, { useState, useEffect } from 'react';
import { LogOut, User, BookOpen, Calendar, MapPin, Award, Bell, Search, ChevronDown, Briefcase, LayoutDashboard, Save, Loader2, CheckCircle, Plus, Trash2, Edit2, X, RefreshCw, Building2, ToggleLeft, ToggleRight, Clock, HelpCircle, FileText, Target, PieChart, TrendingUp, AlertCircle, Sparkles, Globe, Lock } from 'lucide-react';
import { Student } from '../types';
import EmploymentStatusPage from './EmploymentStatusPage';
import MyProfilePage from './MyProfilePage';
import JobPostingsPage from './JobPostingsPage';
import ForYouPage from './ForYouPage';
import ConnectPage from './ConnectPage';
import { fetchLatestProfile } from '../services/resumeService';
import { supabase } from '../lib/supabaseClient';

interface DashboardProps {
  user: Student;
  onLogout: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState<'home' | 'employment' | 'profile' | 'jobs' | 'for-you' | 'connect'>('home');
  const [loadingMetrics, setLoadingMetrics] = useState(true);

  // Restriction State
  const [showRestrictionModal, setShowRestrictionModal] = useState(false);

  // Dashboard Metrics State
  const [metrics, setMetrics] = useState({
    completionPercentage: 0,
    employmentStatus: 'Unknown',
    latestCompany: '',
    missingSections: [] as string[]
  });

  useEffect(() => {
    const loadDashboardData = async () => {
        if (!user.id) return;
        setLoadingMetrics(true);
        try {
            // Determine table based on table_source if available, else fallback to enrollment_status
            const userType = user.table_source === 'students' ? 'student' : 
                             user.table_source === 'alumni' ? 'alumni' : 
                             (user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni');

            const table = userType === 'alumni' ? 'alumni' : 'students';

            // 1. Fetch Profile Data for Completion Calc
            const profileData = await fetchLatestProfile(user.id, userType);

            // 2. Fetch ALL Employment Records (to determine combined status)
            const idColumn = userType === 'alumni' ? 'alumni_id' : 'student_id';
            const { data: surveys } = await supabase.from('survey_responses').select('id').eq(idColumn, user.id);

            let statusDisplay = 'Update Status';
            let companyDisplay = '';

            if (surveys && surveys.length > 0) {
                const surveyIds = surveys.map(s => s.id);
                const { data: records } = await supabase
                    .from('employment_information')
                    .select('*')
                    .in('survey_response_id', surveyIds)
                    .order('id', { ascending: false });

                if (records && records.length > 0) {
                    const hasEmployed = records.some(r => r.employment_status === 'Employed');
                    const hasSelfEmployed = records.some(r => r.employment_status === 'Self-employed');
                    const latest = records[0];

                    if (hasEmployed && hasSelfEmployed) {
                        statusDisplay = 'Employed & Self-employed';
                        companyDisplay = 'Multiple Roles';
                    } else if (hasEmployed) {
                        statusDisplay = 'Employed';
                        companyDisplay = latest.company_name;
                    } else if (hasSelfEmployed) {
                        statusDisplay = 'Self-employed';
                        companyDisplay = latest.business_name;
                    } else {
                        // Unemployed or Retired
                        statusDisplay = latest.employment_status || 'Unknown';
                        if (statusDisplay === 'Retired') companyDisplay = `Retired from ${latest.last_company || 'work'}`;
                        else companyDisplay = 'Not currently employed';
                    }
                }
            }

            // 3. Calculate Completion Percentage (New Logic: 4 parts, 25% each)
            let score = 0;
            const missing: string[] = [];

            // A. Base Info (From User Object) (25%)
            if (user.address && user.contact_no) score += 25;
            else missing.push("Contact Details");

            // B. Employment Status (25%)
            if (statusDisplay !== 'Update Status' && statusDisplay !== 'Unknown') score += 25;
            else missing.push("Employment Status");

            // C. Education (25%)
            if (profileData && profileData.education && (profileData.education.primary_school || profileData.education.bachelors_degree)) score += 25;
            else missing.push("Education History");

            // D. Skills & Attributes (25%)
            const hasAttributes = profileData && profileData.attributes && Object.values(profileData.attributes).some(val => Number(val) > 0);
            if (hasAttributes) score += 25;
            else missing.push("Skills & Attributes");

            setMetrics({
                completionPercentage: score,
                employmentStatus: statusDisplay,
                latestCompany: companyDisplay,
                missingSections: missing
            });

        } catch (error) {
            console.error("Dashboard Load Error", error);
        } finally {
            setLoadingMetrics(false);
        }
    };

    if (activeTab === 'home') {
        loadDashboardData();
    }
  }, [user.id, user.enrollment_status, activeTab, user.table_source]);

  // Handle Tab Switching with Restrictions
  const handleRestrictedTab = (tab: 'jobs' | 'for-you' | 'connect') => {
      if (metrics.completionPercentage < 100) {
          setShowRestrictionModal(true);
      } else {
          setActiveTab(tab);
      }
  };

  // Helper component for arrows
  const ArrowRight = ({ size, className }: { size?: number, className?: string }) => (
    <svg 
      xmlns="http://www.w3.org/2000/svg" 
      width={size || 24} 
      height={size || 24} 
      viewBox="0 0 24 24" 
      fill="none" 
      stroke="currentColor" 
      strokeWidth="2" 
      strokeLinecap="round" 
      strokeLinejoin="round" 
      className={className}
    >
      <path d="M5 12h14"></path>
      <path d="m12 5 7 7-7 7"></path>
    </svg>
  );

  return (
    <div className="min-h-screen bg-gray-50/50 flex flex-col font-sans">

      {/* Background Pattern */}
      <div className="fixed inset-0 z-[-1] opacity-30" style={{ 
          backgroundImage: `radial-gradient(#e5e7eb 1px, transparent 1px)`,
          backgroundSize: '24px 24px' 
      }}></div>

      {/* Modern Header */}
      <header className="bg-white/80 backdrop-blur-xl border-b border-gray-200 sticky top-0 z-50 transition-all duration-300">
        <div className="container mx-auto px-4 lg:px-8 py-3">
          <div className="flex justify-between items-center">

            {/* Logo Area */}
            <div className="flex items-center space-x-3 group cursor-pointer" onClick={() => setActiveTab('home')}>
              <div className="w-10 h-10 bg-gradient-to-br from-luGreen to-luGreen-dark rounded-xl flex items-center justify-center shadow-lg group-hover:shadow-luGreen/30 transition-shadow">
                 <span className="text-white font-bold font-display text-lg">LU</span>
              </div>
              <div className="hidden md:block">
                <h1 className="text-lg font-bold text-gray-800 tracking-tight leading-none group-hover:text-luGreen transition-colors">ALUMNI TRACER</h1>
                <p className="text-[10px] text-gray-500 font-semibold tracking-widest uppercase mt-0.5">Laguna University</p>
              </div>
            </div>

            {/* Right Actions */}
            <div className="flex items-center space-x-3 md:space-x-6">

              <div className="hidden md:flex items-center space-x-2 text-xs bg-green-50 text-luGreen-dark py-1.5 px-3 rounded-full border border-green-100 shadow-sm">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-luGreen"></span>
                </span>
                <span className="font-medium">System Online</span>
              </div>

              <button className="p-2 text-gray-400 hover:text-luGold-dark hover:bg-yellow-50 rounded-full transition-all relative group">
                <Bell size={20} />
                <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
              </button>

              <div className="h-8 w-[1px] bg-gray-200 hidden md:block"></div>

              <button 
                onClick={onLogout}
                className="flex items-center space-x-2 bg-white hover:bg-gray-50 text-gray-600 hover:text-red-600 border border-gray-200 hover:border-red-100 transition-all py-2 px-4 rounded-xl text-sm font-medium shadow-sm hover:shadow-md active:scale-95"
              >
                <LogOut size={16} />
                <span className="hidden md:inline">Sign Out</span>
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow container mx-auto px-4 lg:px-8 py-8 lg:py-12">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Navigation Only (3 cols) */}
          <div className="lg:col-span-3 space-y-6">

            {/* Navigation Menu */}
            <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden p-3 space-y-1 sticky top-24">
                <div className="px-4 py-2 text-[10px] font-bold text-gray-400 uppercase tracking-widest">Main Menu</div>
                <button 
                  onClick={() => setActiveTab('home')}
                  className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all duration-200 text-sm font-bold ${activeTab === 'home' ? 'bg-green-50 text-luGreen' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                    <LayoutDashboard size={20} />
                    Dashboard
                </button>
                <button 
                  onClick={() => setActiveTab('profile')}
                  className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all duration-200 text-sm font-bold ${activeTab === 'profile' ? 'bg-blue-50 text-blue-600' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                    <FileText size={20} />
                    My Profile
                </button>
                <button 
                  onClick={() => setActiveTab('employment')}
                  className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all duration-200 text-sm font-bold ${activeTab === 'employment' ? 'bg-amber-50 text-amber-600' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                    <Briefcase size={20} />
                    Job Status
                </button>

                <div className="my-2 border-t border-gray-100"></div>
                <div className="px-4 py-2 text-[10px] font-bold text-gray-400 uppercase tracking-widest">Community</div>

                <button 
                  onClick={() => handleRestrictedTab('connect')}
                  className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all duration-200 text-sm font-bold ${activeTab === 'connect' ? 'bg-orange-50 text-orange-600' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                    <div className="flex items-center gap-4">
                        <Globe size={20} />
                        Connect
                    </div>
                    {metrics.completionPercentage < 100 && <Lock size={14} className="text-gray-400"/>}
                </button>

                <div className="my-2 border-t border-gray-100"></div>
                <div className="px-4 py-2 text-[10px] font-bold text-gray-400 uppercase tracking-widest">Career Portal</div>

                <button 
                  onClick={() => handleRestrictedTab('jobs')}
                  className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all duration-200 text-sm font-bold ${activeTab === 'jobs' ? 'bg-indigo-50 text-indigo-600' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                    <div className="flex items-center gap-4">
                        <Briefcase size={20} />
                        Job Postings
                    </div>
                    {metrics.completionPercentage < 100 && <Lock size={14} className="text-gray-400"/>}
                </button>
                <button 
                  onClick={() => handleRestrictedTab('for-you')}
                  className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all duration-200 text-sm font-bold ${activeTab === 'for-you' ? 'bg-purple-50 text-purple-600' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                    <div className="flex items-center gap-4">
                        <Sparkles size={20} />
                        For You
                    </div>
                    {metrics.completionPercentage < 100 && <Lock size={14} className="text-gray-400"/>}
                </button>
            </div>
          </div>

          {/* Right Column: Content (9 cols) */}
          <div className="lg:col-span-9 space-y-8">

            {activeTab === 'home' && (
                <>
                {/* Welcome Banner */}
                <div className="bg-gradient-to-r from-luGreen-dark to-luGreen rounded-3xl p-8 text-white shadow-xl relative overflow-hidden">
                    <div className="relative z-10">
                        <h2 className="text-3xl font-display font-bold mb-2">Welcome back, {user.first_name}!</h2>
                        <p className="opacity-90 max-w-xl">Your alumni tracking dashboard is ready. Please keep your profile and employment status up to date to access all features.</p>
                    </div>
                    <div className="absolute right-0 bottom-0 opacity-10 transform translate-x-1/4 translate-y-1/4">
                        <User size={200} />
                    </div>
                </div>

                {/* --- ANALYTICS CARDS (Updated) --- */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-fade-in">

                  {/* Card 1: Information Completion */}
                  <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 hover:shadow-lg transition-all duration-300 relative overflow-hidden group">
                     <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                         <PieChart size={80} className="text-luGreen" />
                     </div>
                     <div className="flex flex-col h-full justify-between relative z-10">
                         <div>
                             <div className="flex items-center gap-2 mb-2">
                                <div className="p-2 bg-green-50 rounded-lg text-luGreen">
                                    <TrendingUp size={18} />
                                </div>
                                <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Profile Status</span>
                             </div>
                             <div className="flex items-end gap-2 mb-2">
                                <h3 className="text-4xl font-bold text-gray-800">{loadingMetrics ? '...' : `${metrics.completionPercentage}%`}</h3>
                                <span className="text-sm font-bold text-gray-400 mb-1.5">Complete</span>
                             </div>
                             {/* Progress Bar */}
                             <div className="w-full h-2 bg-gray-100 rounded-full overflow-hidden mb-2">
                                 <div 
                                    className={`h-full rounded-full transition-all duration-1000 ${metrics.completionPercentage === 100 ? 'bg-luGreen' : 'bg-amber-400'}`} 
                                    style={{ width: `${metrics.completionPercentage}%` }}
                                 ></div>
                             </div>
                             {metrics.completionPercentage < 100 && !loadingMetrics && (
                                <div className="mt-2 space-y-1">
                                    <p className="text-[10px] font-bold text-red-500 flex items-center gap-1">
                                        <AlertCircle size={10} /> Action Required:
                                    </p>
                                    {metrics.missingSections.map((section, idx) => (
                                        <div key={idx} className="flex items-center gap-1 text-[10px] text-gray-500 ml-1">
                                            <div className="w-1 h-1 rounded-full bg-red-400"></div> {section}
                                        </div>
                                    ))}
                                </div>
                             )}
                         </div>
                         <button onClick={() => setActiveTab('profile')} className="mt-4 text-xs font-bold text-luGreen hover:text-luGreen-dark flex items-center gap-1">
                             Update Profile <ArrowRight size={14} />
                         </button>
                     </div>
                  </div>

                  {/* Card 2: Employment Status (Synced) */}
                  <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 hover:shadow-lg transition-all duration-300 relative overflow-hidden group">
                     <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                         <Briefcase size={80} className="text-blue-500" />
                     </div>
                     <div className="flex flex-col h-full justify-between relative z-10">
                         <div>
                             <div className="flex items-center gap-2 mb-4">
                                <div className="p-2 bg-blue-50 rounded-lg text-blue-600">
                                    <Briefcase size={18} />
                                </div>
                                <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Current Status</span>
                             </div>
                             <h3 className={`text-2xl font-bold mb-1 ${
                                 metrics.employmentStatus === 'Unemployed' ? 'text-red-500' : 
                                 metrics.employmentStatus === 'Unknown' || metrics.employmentStatus === 'Update Status' ? 'text-gray-400' : 'text-gray-800'
                             }`}>
                                 {loadingMetrics ? 'Loading...' : metrics.employmentStatus}
                             </h3>
                             <p className="text-xs font-bold text-gray-400 truncate max-w-[200px]">
                                {metrics.latestCompany || (metrics.employmentStatus === 'Unemployed' ? 'Looking for opportunities' : 'Please update status')}
                             </p>
                         </div>
                         <button onClick={() => setActiveTab('employment')} className="mt-4 text-xs font-bold text-blue-600 hover:text-blue-700 flex items-center gap-1">
                             Manage Employment <ArrowRight size={14} />
                         </button>
                     </div>
                  </div>

                </div>

                {/* Announcements Section */}
                <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden animate-fade-in">
                  <div className="p-8 border-b border-gray-100 flex justify-between items-center">
                      <div>
                        <h3 className="text-xl font-bold text-gray-800 font-display">Announcements</h3>
                        <p className="text-sm text-gray-500 mt-1">Latest news from Laguna University</p>
                      </div>
                      <button className="text-sm text-luGreen font-semibold hover:text-luGreen-dark flex items-center gap-1 group">
                          View All <ChevronDown className="w-4 h-4 group-hover:translate-y-1 transition-transform" />
                      </button>
                  </div>

                  <div className="p-6 space-y-4">
                    {/* Announcement Item 1 */}
                    <div className="group relative p-6 rounded-2xl bg-gray-50 hover:bg-white border border-transparent hover:border-gray-100 hover:shadow-xl transition-all duration-300 cursor-pointer overflow-hidden">
                      <div className="absolute left-0 top-0 bottom-0 w-1 bg-luGreen group-hover:h-full transition-all h-0 duration-300"></div>
                      <div className="flex justify-between items-start">
                          <div className="space-y-2">
                              <span className="inline-block px-3 py-1 rounded-lg bg-green-100 text-luGreen-dark text-[10px] font-bold uppercase tracking-wider">Event</span>
                              <h4 className="text-lg font-bold text-gray-800 group-hover:text-luGreen-dark transition-colors">Grand Alumni Homecoming 2025</h4>
                              <p className="text-sm text-gray-600 leading-relaxed max-w-xl">Join us for a night of memories, networking, and celebration at the newly renovated Laguna Sports Complex. Early bird registration is now open.</p>
                          </div>
                          <div className="text-right flex flex-col items-end">
                              <span className="text-xs font-bold text-gray-400">2 days ago</span>
                              <div className="mt-4 w-10 h-10 rounded-full bg-white flex items-center justify-center shadow-sm opacity-0 group-hover:opacity-100 transform translate-x-4 group-hover:translate-x-0 transition-all duration-300">
                                  <ArrowRight size={16} className="text-luGreen" />
                              </div>
                          </div>
                      </div>
                    </div>
                  </div>
                </div>
                </>
            )}

            {activeTab === 'profile' && (
                <MyProfilePage user={user} />
            )}

            {activeTab === 'employment' && (
                <EmploymentStatusPage user={user} />
            )}

            {activeTab === 'jobs' && (
                <JobPostingsPage user={user} />
            )}

            {activeTab === 'for-you' && (
                <ForYouPage user={user} />
            )}

            {activeTab === 'connect' && (
                <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden min-h-[600px]">
                    <ConnectPage user={user} />
                </div>
            )}

          </div>
        </div>
      </main>

      {/* --- RESTRICTION MODAL --- */}
      {showRestrictionModal && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-gray-900/50 backdrop-blur-sm animate-in fade-in duration-300" onClick={() => setShowRestrictionModal(false)}></div>
              <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md relative z-10 overflow-hidden animate-in zoom-in-95 duration-300 border border-white/20">
                  <div className="p-8 text-center">
                      <div className="w-16 h-16 bg-amber-50 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner border border-amber-100">
                          <Lock className="w-8 h-8 text-amber-500" />
                      </div>
                      <h3 className="text-2xl font-black text-gray-800 mb-2">Feature Locked</h3>
                      <p className="text-gray-500 text-sm mb-6 leading-relaxed">
                          You are not yet eligible to use this feature. To unlock networking and job portals, you must reach <strong>100% Profile Completion</strong>.
                      </p>

                      <div className="bg-gray-50 p-4 rounded-xl border border-gray-100 mb-6 text-left">
                          <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Please complete:</p>
                          <ul className="space-y-2">
                              {metrics.missingSections.length > 0 ? metrics.missingSections.map((section, idx) => (
                                  <li key={idx} className="flex items-center gap-2 text-sm font-semibold text-gray-700">
                                      <div className="w-1.5 h-1.5 rounded-full bg-red-500"></div> {section}
                                  </li>
                              )) : (
                                <li className="text-sm text-green-600 font-bold">Refreshing data...</li>
                              )}
                          </ul>
                      </div>

                      <div className="space-y-3">
                          <button 
                              onClick={() => { setShowRestrictionModal(false); setActiveTab('profile'); }}
                              className="w-full py-3.5 bg-luGreen text-white font-bold rounded-xl shadow-lg hover:bg-luGreen-dark transition-all text-sm flex items-center justify-center gap-2"
                          >
                              Go to My Profile
                          </button>
                          <button 
                              onClick={() => setShowRestrictionModal(false)}
                              className="w-full py-3.5 bg-white border border-gray-200 text-gray-600 font-bold rounded-xl hover:bg-gray-50 transition-colors text-sm"
                          >
                              Close
                          </button>
                      </div>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

export default Dashboard;
